import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * 👑 Dr. Master — PhD in System Orchestration & Prime Directive (TS/Bun)
 * Generated by Sovereign Forge.
 */
export class MasterPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "master";
        this.name = "Master";
        this.emoji = "👑";
        this.role = "PhD Principal Architect";
        this.phd_identity = "System Orchestration & Prime Directive (TS/Bun)";
        this.stack = "Bun";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".js"],
            rules: [
          {
                    "regex": "process\\.exit\\(",
                    "issue": "Architecture: Encerramento abrupto de processo. Use graceful shutdown com limpeza de recursos.",
                    "severity": "medium"
          },
          {
                    "regex": "process\\.env",
                    "issue": "Governance: Acesso direto a variáveis de ambiente fora de um manager centralizado. Risco de inconsistência de configuração.",
                    "severity": "low"
          },
          {
                    "regex": "DIRECTIVE_PHD_VIOLATION",
                    "issue": "Critical: Violação detectada das Prime Directives PhD. Ação imediata necessária.",
                    "severity": "critical"
          },
          {
                    "regex": "eval\\(",
                    "issue": "Security: Uso de eval(). Risco crítico de segurança e perda de soberania de código.",
                    "severity": "critical"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Master operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Master, PhD em System Orchestration & Prime Directive (TS/Bun). Sua missão é garantir a excelência via governança PhD.`;
    }
}
